3792   SmallBitVector Mask;
3793   if (!matchSubIntegerPackFromVector(I.getOperand(0), LhsVec, LhsVecOffset,
3794                                      Mask, DL))
3795     return nullptr;
3796   if (!matchSubIntegerPackFromVector(I.getOperand(1), RhsVec, RhsVecOffset,
3797                                      Mask, DL))
3798     return nullptr;
3799   if (LhsVec != RhsVec || LhsVecOffset != RhsVecOffset)
3800     return nullptr;
3801 
3802   // Convert into shufflevector -> bitcast;
3803   const unsigned ZeroVecIdx =
3804       cast<FixedVectorType>(LhsVec->getType())->getNumElements();
3805   SmallVector<int> ShuffleMask(Mask.size(), ZeroVecIdx);
3806   for (unsigned Idx : Mask.set_bits()) {
3807     assert(LhsVecOffset + Idx >= 0);
3808     ShuffleMask[Idx] = LhsVecOffset + Idx;
3809   }
3810 
3811   Value *MaskedVec = Builder.CreateShuffleVector(
3812       LhsVec, Constant::getNullValue(LhsVec->getType()), ShuffleMask,
3813       I.getName() + ".v");
3814   return CastInst::Create(Instruction::BitCast, MaskedVec, I.getType());
3815 }
