3817 /// Match \p V as "lshr -> mask -> zext -> shl".
3818 ///
3819 /// \p Int is the underlying integer being extracted from.
3820 /// \p Mask is a bitmask identifying which bits of the integer are being
3821 /// extracted. \p Offset identifies which bit of the result \p V corresponds to
3822 /// the least significant bit of \p Int
3823 static bool matchZExtedSubInteger(Value *V, Value *&Int, APInt &Mask,
3824                                   uint64_t &Offset, bool &IsShlNUW,
3825                                   bool &IsShlNSW) {
3826   Value *ShlOp0;
3827   uint64_t ShlAmt = 0;
3828   if (!match(V, m_OneUse(m_Shl(m_Value(ShlOp0), m_ConstantInt(ShlAmt)))))
3829     return false;
3830 
3831   IsShlNUW = cast<BinaryOperator>(V)->hasNoUnsignedWrap();
3832   IsShlNSW = cast<BinaryOperator>(V)->hasNoSignedWrap();
3833 
3834   Value *ZExtOp0;
3835   if (!match(ShlOp0, m_OneUse(m_ZExt(m_Value(ZExtOp0)))))
3836     return false;
3837 
3838   Value *MaskedOp0;
3839   const APInt *ShiftedMaskConst = nullptr;
3840   if (!match(ZExtOp0, m_CombineOr(m_OneUse(m_And(m_Value(MaskedOp0),
3841                                                  m_APInt(ShiftedMaskConst))),
3842                                   m_Value(MaskedOp0))))
3843     return false;
3844 
3845   uint64_t LShrAmt = 0;
3846   if (!match(MaskedOp0,
3847              m_CombineOr(m_OneUse(m_LShr(m_Value(Int), m_ConstantInt(LShrAmt))),
3848                          m_Value(Int))))
3849     return false;
3850 
3851   if (LShrAmt > ShlAmt)
3852     return false;
3853   Offset = ShlAmt - LShrAmt;
3854 
3855   Mask = ShiftedMaskConst ? ShiftedMaskConst->shl(LShrAmt)
3856                           : APInt::getBitsSetFrom(
3857                                 Int->getType()->getScalarSizeInBits(), LShrAmt);
3858 
3859   return true;
3860 }
